<template lang="en">
    <div>
        <loader :isVisible="isLoading"></loader>
        <dynamic-form v-show="false" lang="en" ref="BarcodeReport" v-if="DataLoaded" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit"></dynamic-form>
        <div class="row placeholder">
            <div class="col-md-12 p-0">
                <ReportViewer v-if="parameter.length>0" :parameter="parameter" :reportPath="reportPath"></ReportViewer>
            </div>
        </div>
    </div>
    </template>
    <script>
    import '@boldreports/javascript-reporting-controls/Scripts/bold.report-designer.min';
    import '@boldreports/javascript-reporting-controls/Scripts/bold.report-viewer.min';
    import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.bulletgraph.min';
    import '@boldreports/javascript-reporting-controls/Scripts/data-visualization/ej.chart.min';
    import DataServices from "../services/DataService";
    import ReportViewer from '../views/HrReport/ReportViewer.vue';
    export default {
        components: {
            ReportViewer
        },
        data() {
            return {
                isLoading: false,
                 reportPath: null,
                 parameter: [],
                FormSchema: [{
                        layoutType: "triple",
                        Data: [
                            {
                                astype: "MultiSelectField",
                                label: this.$t("User"),
                                name: "User",
                                value: "",
                                placeholder: this.$t('Select') + " " + this.$t('User'),
                                mode: "tag",
                                config: {
                                    options: []
                                }

                            },
                            {
                                astype: "MultiSelectField",
                                label: this.$t("Skill"),
                                name: "Skill",
                                value: "",
                                placeholder: this.$t('Select') + " " + this.$t('Skill'),
                                mode: "tag",
                                config: {
                                    options: [],
                                  
                                },
                            },
                            {
                                astype: "MultiSelectField",
                                label: this.$t("Trainer"),
                                name: "Trainer",
                                value: "",
                                placeholder: this.$t('Select') + " " + this.$t('Trainer'),
                                mode: "tag",
                                config: {
                                    options: [],
                                    // onChange: this.onChangeDropdown,
                                    // onRemove: this.removeRecord,
                                },
                            },
                            {
                                astype: "MultiSelectField",
                                label: this.$t("Department"),
                                name: "Department",
                                value: "",
                                placeholder: this.$t('Select') + " " + this.$t('Department'),
                                mode: "tag",
                                config: {
                                    options: [],
                                    // onChange: this.onChangeDropdown,
                                    // onRemove: this.removeRecord,
                                },
                            },
                            {
                              astype: "DateField",
                              label: this.$t("Date Range (M/D/YY)"),
                              name: "dtFrom",
                              value: "",
                              placeholder: "10/12/2022 12:AM",
  
                              config: {
                                  format: "M/D/YYYY"
                              },
                            },
                          {
                              astype: "DateField",
                              label: '',
                              name: "dtTO",
                              value: "",
                              placeholder: "10/12/2022 12:AM",
  
                              config: {
                                  format: "M/D/YYYY"
                              },
                          },
                        ],
                    },
                  
                ],
                buttons: [{
                        type: "submit",
                        class: "btn btn-success",
                        text: "<i class='fa fa-search pr-2'></i>Search",
                    },
                    {
                        type: "button",
                        class: "btn btn-danger",
                        text: "<i class='fa fa-close pr-2'></i>Clear all",
                        onClick: this.ClearAll
                    },
                ],
                DataLoaded: 0,
            };
        },
        created: async function () {
            debugger
            var vm = this;
            vm.userId = vm.GetUserInfo.ID;
            vm.companyId = vm.GetUserInfo.CompanyId;
            vm.DataLoaded = 1;
            await vm.LoadUsersByCompanyId();
            await vm.BindDepartment(); 
            await vm.GetSkill(); 
            await vm.GetTrainer(); 
        },
        methods: {
    
            ClearAll: function () {
                var vm = this;
                (vm.FormSchema)[0].Data[0].value = '';
                (vm.FormSchema)[0].Data[1].value = '';
                (vm.FormSchema)[0].Data[2].value = '';
                (vm.FormSchema)[0].Data[3].value = '';
                (vm.FormSchema)[0].Data[4].value = '';
                (vm.FormSchema)[0].Data[5].value = '';
                // vm.parameter = [];
            },
    
            onSubmit(e) {
                var reportviewerObj = $("#viewer").data("boldReportViewer");
                if(reportviewerObj != null)
                {
                    reportviewerObj.destroy();
                }
                var vm = this;
                vm.isLoading=true;
                vm.reportPath = '';      
                vm.parameter=[];
                debugger;
                let myObj = {
                    reportName: "usertrainingreport",
                    userIds: Array(e.User.length) > 0 ? e.User.map(item => item.value).join(",") : '',
                    SkillsIds:  e.Skill.length > 0 ? e.Skill.map(item => item.value).join(",") : '',
                    TrainerIds:  e.Trainer.length > 0 ? e.Trainer.map(item => item.value).join(",") : '',
                    dateFrom:e.dtFrom,
                    dateTo:e.dtTO
                    ,
                }
                var postString = JSON.stringify(myObj);   
                 DataServices.ReportMain(postString).then(function (response) {
                    debugger;
                    vm.reportPath = response.data.reportpath;
                    vm.parameter = response.data.parameters;
                })
                vm.isLoading=false;
            },
    
         LoadUsersByCompanyId: async function() {
            debugger;
            var vm = this;
            var url = `isIncludeLoginUserId=1&approvalGroupIds=&approvalChainIds=&moduleName=training&DepartmentIds`;
            await DataServices.GetUsers(url).then(response => {
                if (response.data) {
                    var json = response.data;
                    if (json != null) {
                        json.forEach((item, index) => {
                            vm.FormSchema[0].Data[0].config.options.push({
                                value: item.UserId,
                                name: item.UserName
                            })
                        })
                    }
                }
            });
        },
      
        BindDepartment: async function () {
                var vm = this;
                var url = `id=&moduleName=HIRINGReport&type=DEPARTMENT&search=&refId`;
                await DataServices.GetDDLData(url).then((response) => {
                    if (response.data.DATA.length > 0) {
                        var DepartmentData = response.data.DATA;
                        DepartmentData.forEach(element => {
                            var Obj = {
                                name: element.name,
                                value: element.value
                            }
                            vm.FormSchema[0].Data[3].config.options.push(Obj);
                        });  
                        vm.$refs.BarcodeReport.UpdateKeyValue();
                    }
                });
            },

            GetSkill: async function() {
            debugger;
            var vm = this;
            await DataServices.GetCompanySkills().then(response => {
                debugger;
                if (response.data) {
                    var json = response.data;
                    if (json != null) {
                        json.forEach((item, index) => {
                            vm.FormSchema[0].Data[1].config.options.push({
                                value: item.SKILL_ID,
                                name: item.SKILL_NAME
                            })
                        })
                    }
                }
            });
        },

        GetTrainer: async function() {
            debugger;
            var vm = this;
            await DataServices.GetTrainer().then(response => {
                debugger;
                if (response.data) {
                    var json = response.data;
                    if (json != null) {
                        json.forEach((item, index) => {
                            vm.FormSchema[0].Data[2].config.options.push({
                                value: item.USER_ID,
                                name: item.TRAINER_NAME
                            })
                        })
                    }
                }
            });
        },
        }
    };
    </script>
    